import { ProjectInfo, Division } from '../types';

declare const jspdf: any;

export const generatePdf = (
    projectInfo: ProjectInfo,
    divisions: Division[],
    subTotalWithOverhead: number,
    marginAmount: number,
    grandTotal: number,
    isClientView: boolean
) => {
    const { jsPDF } = jspdf;
    const doc = new jsPDF();

    // Header Branding/Title
    doc.setFillColor(63, 81, 181); // Indigo color
    doc.rect(0, 0, 210, 40, 'F');

    doc.setFontSize(24);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(255, 255, 255);
    doc.text("CONSTRUCTION COST ESTIMATE", 14, 25);

    // Project Info Header Section
    doc.setFillColor(245, 247, 250);
    doc.rect(0, 40, 210, 35, 'F');

    doc.setFontSize(10);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(100, 116, 139); // Slate-500
    doc.text("PROJECT DETAILS", 14, 50);

    doc.setFontSize(12);
    doc.setTextColor(30, 41, 59); // Slate-800
    doc.text(`Job Name: ${projectInfo.jobName}`, 14, 58);
    doc.text(`Address: ${projectInfo.address}`, 14, 66);

    // Metrics in Header
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139);
    doc.text("SPECIFICATIONS", 140, 50);
    doc.setFontSize(11);
    doc.setTextColor(30, 41, 59);
    doc.text(`Total Area: ${projectInfo.squareFeet.toLocaleString()} SQFT`, 140, 58);
    doc.text(`Total Rooms: ${projectInfo.rooms}`, 140, 66);

    const head = isClientView
        ? [['Service', 'Description', 'Total']]
        : [['Cost Code', 'Service', 'Description', 'Total']];

    const body: any[] = [];

    divisions.forEach(div => {
        const itemsToInclude = div.items.filter(item => 
            (item.material + item.labor + item.equipment + item.subContract) > 0 || (item.service.trim() !== '' && item.description.trim() !== '')
        );

        if (itemsToInclude.length > 0) {
            const divisionTotal = itemsToInclude.reduce((acc, item) => {
                const baseTotal = item.material + item.labor + item.equipment + item.subContract;
                return acc + (baseTotal * (1 + projectInfo.add / 100));
            }, 0);

            // Add division header row
            body.push([
                {
                    content: `${div.costCode} - ${div.title}`,
                    colSpan: isClientView ? 2 : 3,
                    styles: { fontStyle: 'bold', fillColor: [241, 245, 249], textColor: [30, 41, 59], cellPadding: 3 }
                },
                {
                    content: divisionTotal.toLocaleString('en-US', { style: 'currency', currency: 'USD' }),
                    styles: { fontStyle: 'bold', halign: 'right', fillColor: [241, 245, 249], textColor: [30, 41, 59], cellPadding: 3 }
                }
            ]);

            // Add line item rows
            itemsToInclude.forEach(item => {
                const itemBaseTotal = item.material + item.labor + item.equipment + item.subContract;
                const itemTotalWithOverhead = itemBaseTotal * (1 + projectInfo.add / 100);

                if (isClientView) {
                    body.push([
                        item.service,
                        item.description,
                        itemTotalWithOverhead.toLocaleString('en-US', { style: 'currency', currency: 'USD' })
                    ]);
                } else {
                    body.push([
                        item.costCode,
                        item.service,
                        item.description,
                        itemTotalWithOverhead.toLocaleString('en-US', { style: 'currency', currency: 'USD' })
                    ]);
                }
            });
        }
    });

    let finalY = 85;
    if (body.length > 0) {
        doc.autoTable({
            startY: 85,
            head: head,
            body: body,
            theme: 'grid',
            headStyles: { fillColor: [63, 81, 181], textColor: 255, fontStyle: 'bold' },
            styles: {
                cellPadding: 3,
                fontSize: 9,
                lineColor: [226, 232, 240]
            },
            columnStyles: isClientView
                ? { 
                    0: { cellWidth: 60 },
                    1: { cellWidth: 'auto' },
                    2: { halign: 'right', cellWidth: 40, fontStyle: 'bold' } 
                }
                : {
                    0: { cellWidth: 25 },
                    1: { cellWidth: 50 },
                    2: { cellWidth: 'auto' },
                    3: { halign: 'right', cellWidth: 40, fontStyle: 'bold' }
                  },
            didDrawPage: (data: any) => {
                finalY = data.cursor.y;
            }
        });
    } else {
        doc.setFontSize(12);
        doc.setTextColor(100, 116, 139);
        doc.text("No line items recorded for this estimate.", 14, 95);
        finalY = 100;
    }

    // Calculations for metrics
    const costPerSqFt = projectInfo.squareFeet > 0 ? grandTotal / projectInfo.squareFeet : 0;
    const costPerRoom = projectInfo.rooms > 0 ? grandTotal / projectInfo.rooms : 0;

    // Summary Section
    const summaryWidth = 80;
    const summaryX = 210 - summaryWidth - 14;
    let summaryY = finalY + 15;

    // Ensure summary doesn't overflow page
    if (summaryY > 250) {
        doc.addPage();
        summaryY = 20;
    }

    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(30, 41, 59);
    doc.text("Estimate Summary", 14, summaryY);

    const summaryTable = [
        ['Subtotal (incl. Overhead)', subTotalWithOverhead.toLocaleString('en-US', { style: 'currency', currency: 'USD' })],
        [`Margin (${projectInfo.margin}%)`, marginAmount.toLocaleString('en-US', { style: 'currency', currency: 'USD' })],
        ['Grand Total', { content: grandTotal.toLocaleString('en-US', { style: 'currency', currency: 'USD' }), styles: { fontStyle: 'bold', fontSize: 12, textColor: [63, 81, 181] } }],
        ['Cost per Square Foot', costPerSqFt.toLocaleString('en-US', { style: 'currency', currency: 'USD' })],
        ['Cost per Room', costPerRoom.toLocaleString('en-US', { style: 'currency', currency: 'USD' })]
    ];

    doc.autoTable({
        startY: summaryY + 5,
        body: summaryTable,
        theme: 'plain',
        styles: { fontSize: 10, cellPadding: 2 },
        columnStyles: {
            0: { halign: 'right', cellWidth: 140, textColor: [100, 116, 139] },
            1: { halign: 'right', cellWidth: 40, textColor: [30, 41, 59] }
        }
    });

    const pageCount = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
        doc.setPage(i);
        doc.setFontSize(8);
        doc.setTextColor(150);
        doc.text(`Page ${i} of ${pageCount}`, 210 - 25, 290);
        doc.text(`Estimate generated on ${new Date().toLocaleDateString()}`, 14, 290);
    }

    doc.save(`${projectInfo.jobName.replace(/\s+/g, '_')}_Estimate.pdf`);
};

import React, { useMemo } from 'react';
import { ProjectInfo, Division } from '../types';

interface SummaryProps {
  projectInfo: ProjectInfo;
  divisions: Division[];
  subTotal: number;
  marginAmount: number;
  grandTotal: number;
  isClientView: boolean;
  onClientViewToggle: () => void;
  onGeneratePdf: () => void;
}

const SummaryRow: React.FC<{label: string, value: number, isBold?: boolean}> = ({label, value, isBold}) => (
    <div className={`flex justify-between items-center py-2 ${isBold ? 'font-bold text-lg' : 'text-sm'}`}>
        <span className={isBold ? 'text-gray-800' : 'text-gray-600'}>{label}</span>
        <span className={isBold ? 'text-indigo-600' : 'text-gray-800'}>
            {value.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}
        </span>
    </div>
);

const MetricBox: React.FC<{ label: string; value: number }> = ({ label, value }) => (
    <div className="flex items-center justify-between p-2 bg-gray-100 rounded-lg">
        <span className="text-[10px] uppercase tracking-wider font-bold text-gray-500">{label}</span>
        <span className="text-sm font-bold text-gray-800">{value.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}</span>
    </div>
);


const Summary: React.FC<SummaryProps> = ({ projectInfo, divisions, subTotal, marginAmount, grandTotal, isClientView, onClientViewToggle, onGeneratePdf }) => {
  const sqft = projectInfo.squareFeet > 0 ? projectInfo.squareFeet : 1;

  // Calculate Sitework portion (Div 31, 32, 33)
  const siteworkTotal = useMemo(() => {
    const siteworkDivs = divisions.filter(d => 
        d.costCode.startsWith('31') || 
        d.costCode.startsWith('32') || 
        d.costCode.startsWith('33')
    );

    const baseTotal = siteworkDivs.reduce((acc, div) => {
        return acc + div.items.reduce((sum, item) => sum + (Number(item.material) + Number(item.labor) + Number(item.equipment) + Number(item.subContract)), 0);
    }, 0);

    const withOverhead = baseTotal * (1 + projectInfo.add / 100);
    const withMargin = withOverhead * (1 + projectInfo.margin / 100);
    return withMargin;
  }, [divisions, projectInfo.add, projectInfo.margin]);

  const totalCostPerSqFt = grandTotal / sqft;
  const siteworkCostPerSqFt = siteworkTotal / sqft;
  const buildingOnlyCostPerSqFt = (grandTotal - siteworkTotal) / sqft;
  const costPerRoom = projectInfo.rooms > 0 ? grandTotal / projectInfo.rooms : 0;

  return (
    <footer className="sticky bottom-0 bg-white shadow-[0_-4px_10px_-1px_rgba(0,0,0,0.1)] border-t border-gray-200 p-4 z-50">
      <div className="container mx-auto grid grid-cols-1 lg:grid-cols-4 gap-6 items-center">

        {/* Cost Breakdown Metrics */}
        <div className="lg:col-span-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 gap-2">
            <MetricBox label="Total Cost / SF" value={totalCostPerSqFt} />
            <MetricBox label="Sitework / SF" value={siteworkCostPerSqFt} />
            <MetricBox label="Building / SF (No Sitework)" value={buildingOnlyCostPerSqFt} />
            <MetricBox label="Cost / Room" value={costPerRoom} />
        </div>

        <div className="lg:col-span-2 px-4 border-l border-r border-gray-100">
          <SummaryRow label="Subtotal" value={subTotal} />
          <SummaryRow label={`Margin (${projectInfo.margin}%)`} value={marginAmount} />
          <div className="border-t my-1 border-gray-200"></div>
          <SummaryRow label="Grand Total" value={grandTotal} isBold={true} />
        </div>

        <div className="lg:col-span-1 flex flex-col gap-3">
          <div className="flex items-center justify-between">
            <label htmlFor="client-view-toggle" className="text-sm font-medium text-gray-700">Client View (Hide Costs)</label>
            <button onClick={onClientViewToggle} className={`${isClientView ? 'bg-indigo-600' : 'bg-gray-200'} relative inline-flex h-6 w-11 items-center rounded-full transition-colors`}>
                <span className={`${isClientView ? 'translate-x-6' : 'translate-x-1'} inline-block h-4 w-4 transform rounded-full bg-white transition-transform`}/>
            </button>
          </div>
          <button
            onClick={onGeneratePdf}
            className="w-full bg-indigo-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 shadow-md transition-all active:scale-95"
          >
            Generate Estimate PDF
          </button>
        </div>
      </div>
    </footer>
  );
};

export default Summary;

import React, { useState, useMemo, useCallback } from 'react';
import { initialData } from './data/csiCodes';
import { Division as DivisionType, ProjectInfo, LineItem, ProjectData } from './types';
import Header from './components/Header';
import CostTable from './components/CostTable';
import Summary from './components/Summary';
import { generatePdf } from './services/pdfService';
import { generateXml } from './services/xmlService';

const App: React.FC = () => {
  const [projectInfo, setProjectInfo] = useState<ProjectInfo>({
    jobName: 'Project Name',
    address: '123 Main St',
    rooms: 1,
    squareFeet: 1,
    margin: 10,
    add: 3,
  });
  const [divisions, setDivisions] = useState<DivisionType[]>(initialData);
  const [isClientView, setIsClientView] = useState<boolean>(false);

  const handleProjectInfoChange = useCallback((field: keyof ProjectInfo, value: string | number) => {
    setProjectInfo(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleItemChange = useCallback((divisionId: string, itemId: string, field: keyof LineItem, value: string | number) => {
    setDivisions(prevDivisions =>
      prevDivisions.map(div => {
        if (div.id === divisionId) {
          return {
            ...div,
            items: div.items.map(item => {
              if (item.id === itemId) {
                return { ...item, [field]: value };
              }
              return item;
            }),
          };
        }
        return div;
      })
    );
  }, []);

  const handleAddItem = useCallback((divisionId: string) => {
    setDivisions(prevDivisions =>
      prevDivisions.map(div => {
        if (div.id === divisionId) {
          const newItem: LineItem = {
            id: crypto.randomUUID(),
            costCode: '',
            service: '',
            description: '',
            material: 0,
            labor: 0,
            equipment: 0,
            subContract: 0,
          };
          return {
            ...div,
            items: [...div.items, newItem],
          };
        }
        return div;
      })
    );
  }, []);

  const handleSaveProject = useCallback(() => {
    const projectData: ProjectData = {
      projectInfo,
      divisions,
    };
    const dataStr = JSON.stringify(projectData, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    const fileName = projectInfo.jobName.replace(/\s+/g, '_') || 'project';
    link.download = `${fileName}_estimate.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, [projectInfo, divisions]);

  const handleLoadProject = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result;
        if (typeof text !== 'string') {
          throw new Error('File content is not readable.');
        }
        const data: ProjectData = JSON.parse(text);

        if (data.projectInfo && Array.isArray(data.divisions)) {
          setProjectInfo(data.projectInfo);
          setDivisions(data.divisions);
          alert('Project loaded successfully!');
        } else {
          throw new Error('Invalid project file format.');
        }
      } catch (error: any) {
        console.error("Failed to load project:", error);
        alert(`Failed to load project. Please make sure you are selecting a valid project JSON file. Error: ${error.message}`);
      }
    };
    reader.onerror = () => {
      alert('Error reading file.');
    };
    reader.readAsText(file);
    event.target.value = '';
  }, []);

  const subTotalWithOverhead = useMemo(() => {
    return divisions.reduce((total, div) => {
      return total + div.items.reduce((divTotal, item) => {
        const itemBaseTotal = Number(item.material) + Number(item.labor) + Number(item.equipment) + Number(item.subContract);
        const itemTotalWithOverhead = itemBaseTotal * (1 + projectInfo.add / 100);
        return divTotal + itemTotalWithOverhead;
      }, 0);
    }, 0);
  }, [divisions, projectInfo.add]);

  const marginAmount = useMemo(() => subTotalWithOverhead * (projectInfo.margin / 100), [subTotalWithOverhead, projectInfo.margin]);
  const grandTotal = useMemo(() => subTotalWithOverhead + marginAmount, [subTotalWithOverhead, marginAmount]);

  const handleGeneratePdf = () => {
    generatePdf(projectInfo, divisions, subTotalWithOverhead, marginAmount, grandTotal, isClientView);
  };

  const handleExportExcel = useCallback(() => {
    const projectData: ProjectData = {
      projectInfo,
      divisions,
    };
    const xmlString = generateXml(projectData, subTotalWithOverhead, marginAmount, grandTotal);
    const dataBlob = new Blob([xmlString], { type: 'application/xml' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    const fileName = projectInfo.jobName.replace(/\s+/g, '_') || 'project';
    link.download = `${fileName}_estimate.xml`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, [projectInfo, divisions, subTotalWithOverhead, marginAmount, grandTotal]);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans antialiased">
      <main className="container mx-auto p-4 sm:p-6 lg:p-8 pb-48">
        <Header 
          projectInfo={projectInfo} 
          onChange={handleProjectInfoChange}
          onSave={handleSaveProject}
          onLoad={handleLoadProject}
          onExportExcel={handleExportExcel}
        />
        <CostTable 
          divisions={divisions} 
          on_change={handleItemChange} 
          onAddItem={handleAddItem} 
          isClientView={isClientView} 
          overheadPercent={projectInfo.add}
        />
      </main>
      <Summary 
        projectInfo={projectInfo}
        divisions={divisions}
        subTotal={subTotalWithOverhead}
        marginAmount={marginAmount}
        grandTotal={grandTotal}
        isClientView={isClientView}
        onClientViewToggle={() => setIsClientView(v => !v)}
        onGeneratePdf={handleGeneratePdf}
      />
    </div>
  );
};

export default App;

