        </Table>
    </Worksheet>
</Workbook>`.trim();
};

import React, { useState, useMemo, useCallback } from 'react';
import { initialData } from './data/csiCodes';
import { Division as DivisionType, ProjectInfo, LineItem, ProjectData } from './types';
import Header from './components/Header';
import CostTable from './components/CostTable';
import Summary from './components/Summary';
import { generatePdf } from './services/pdfService';
import { generateXml } from './services/xmlService';

const App: React.FC = () => {
  const [projectInfo, setProjectInfo] = useState<ProjectInfo>({
    jobName: 'Project Name',
    address: '123 Main St',
    rooms: 1,
    squareFeet: 1,
    margin: 10,
    add: 3,
  });
  const [divisions, setDivisions] = useState<DivisionType[]>(initialData);
  const [isClientView, setIsClientView] = useState<boolean>(false);

  const handleProjectInfoChange = useCallback((field: keyof ProjectInfo, value: string | number) => {
    setProjectInfo(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleItemChange = useCallback((divisionId: string, itemId: string, field: keyof LineItem, value: string | number) => {
    setDivisions(prevDivisions =>
      prevDivisions.map(div => {
        if (div.id === divisionId) {
          return {
            ...div,
            items: div.items.map(item => {
              if (item.id === itemId) {
                return { ...item, [field]: value };
              }
              return item;
            }),
          };
        }
        return div;
      })
    );
  }, []);

  const handleAddItem = useCallback((divisionId: string) => {
    setDivisions(prevDivisions =>
      prevDivisions.map(div => {
        if (div.id === divisionId) {
          const newItem: LineItem = {
            id: crypto.randomUUID(),
            costCode: '',
            service: '',
            description: '',
            material: 0,
            labor: 0,
            equipment: 0,
            subContract: 0,
          };
          return {
            ...div,
            items: [...div.items, newItem],
          };
        }
        return div;
      })
    );
  }, []);

  const handleSaveProject = useCallback(() => {
    const projectData: ProjectData = {
      projectInfo,
      divisions,
    };
    const dataStr = JSON.stringify(projectData, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    const fileName = projectInfo.jobName.replace(/\s+/g, '_') || 'project';
    link.download = `${fileName}_estimate.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, [projectInfo, divisions]);

  const handleLoadProject = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result;
        if (typeof text !== 'string') {
          throw new Error('File content is not readable.');
        }
        const data: ProjectData = JSON.parse(text);

        if (data.projectInfo && Array.isArray(data.divisions)) {
          setProjectInfo(data.projectInfo);
          setDivisions(data.divisions);
          alert('Project loaded successfully!');
        } else {
          throw new Error('Invalid project file format.');
        }
      } catch (error: any) {
        console.error("Failed to load project:", error);
        alert(`Failed to load project. Please make sure you are selecting a valid project JSON file. Error: ${error.message}`);
      }
    };
    reader.onerror = () => {
      alert('Error reading file.');
    };
    reader.readAsText(file);
    event.target.value = '';
  }, []);

  const subTotalWithOverhead = useMemo(() => {
    return divisions.reduce((total, div) => {
      return total + div.items.reduce((divTotal, item) => {
        const itemBaseTotal = Number(item.material) + Number(item.labor) + Number(item.equipment) + Number(item.subContract);
        const itemTotalWithOverhead = itemBaseTotal * (1 + projectInfo.add / 100);
        return divTotal + itemTotalWithOverhead;
      }, 0);
    }, 0);
  }, [divisions, projectInfo.add]);

  const marginAmount = useMemo(() => subTotalWithOverhead * (projectInfo.margin / 100), [subTotalWithOverhead, projectInfo.margin]);
  const grandTotal = useMemo(() => subTotalWithOverhead + marginAmount, [subTotalWithOverhead, marginAmount]);

  const handleGeneratePdf = () => {
    generatePdf(projectInfo, divisions, subTotalWithOverhead, marginAmount, grandTotal, isClientView);
  };

  const handleExportExcel = useCallback(() => {
    const projectData: ProjectData = {
      projectInfo,
      divisions,
    };
    const xmlString = generateXml(projectData, subTotalWithOverhead, marginAmount, grandTotal);
    // Use application/vnd.ms-excel which is more likely to trigger Excel's specialized XML handler
    const dataBlob = new Blob([xmlString], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    const fileName = projectInfo.jobName.replace(/\s+/g, '_') || 'project';
    link.download = `${fileName}_estimate.xml`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, [projectInfo, divisions, subTotalWithOverhead, marginAmount, grandTotal]);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans antialiased">
      <main className="container mx-auto p-4 sm:p-6 lg:p-8 pb-48">
        <Header 
          projectInfo={projectInfo} 
          onChange={handleProjectInfoChange}
          onSave={handleSaveProject}
          onLoad={handleLoadProject}
          onExportExcel={handleExportExcel}
        />
        <CostTable 
          divisions={divisions} 
          on_change={handleItemChange} 
          onAddItem={handleAddItem} 
          isClientView={isClientView} 
          overheadPercent={projectInfo.add}
        />
      </main>
      <Summary 
        projectInfo={projectInfo}
        divisions={divisions}
        subTotal={subTotalWithOverhead}
        marginAmount={marginAmount}
        grandTotal={grandTotal}
        isClientView={isClientView}
        onClientViewToggle={() => setIsClientView(v => !v)}
        onGeneratePdf={handleGeneratePdf}
      />
    </div>
  );
};

export default App;

import { ProjectData } from '../types';

const escapeXml = (unsafe: string): string => {
    if (typeof unsafe !== 'string') return '';
    return unsafe.replace(/[<>&'"]/g, (c) => {
        switch (c) {
            case '<': return '&lt;';
            case '>': return '&gt;';
            case '&': return '&amp;';
            case '\'': return '&apos;';
            case '"': return '&quot;';
            default: return c;
        }
    });
};

const createCell = (data: string | number, type: 'String' | 'Number' = 'String', styleId?: string, formula?: string) => {
    const content = typeof data === 'string' ? escapeXml(data) : data;
    const styleAttr = styleId ? ` ss:StyleID="${styleId}"` : '';
    const formulaAttr = formula ? ` ss:Formula="${formula}"` : '';
    return `<Cell${styleAttr}${formulaAttr}><Data ss:Type="${type}">${content}</Data></Cell>`;
};

const createEmptyCells = (count: number) => {
    return Array(count).fill('<Cell/>').join('');
};

export const generateXml = (
    projectData: ProjectData,
    subTotal: number,
    marginAmount: number,
    grandTotal: number
): string => {
    const { projectInfo, divisions } = projectData;

    // Fixed references for Project Info
    // B3: Rooms, B4: SQFT, B5: Overhead, B6: Margin
    const projectInfoRows = `
        <Row>
            ${createCell('Job Name', 'String', 'sBold')}
            ${createCell(projectInfo.jobName)}
        </Row>
        <Row>
            ${createCell('Address', 'String', 'sBold')}
            ${createCell(projectInfo.address)}
        </Row>
        <Row>
            ${createCell('Rooms', 'String', 'sBold')}
            ${createCell(projectInfo.rooms, 'Number')}
        </Row>
        <Row>
            ${createCell('Square Feet', 'String', 'sBold')}
            ${createCell(projectInfo.squareFeet, 'Number')}
        </Row>
        <Row>
            ${createCell('Overhead (%)', 'String', 'sBold')}
            ${createCell(projectInfo.add, 'Number')}
        </Row>
        <Row>
            ${createCell('Margin (%)', 'String', 'sBold')}
            ${createCell(projectInfo.margin, 'Number')}
        </Row>
    `;

    const headerRow = `
        <Row ss:StyleID="sHeader">
            ${createCell('Division')}
            ${createCell('Cost Code')}
            ${createCell('Service')}
            ${createCell('Description')}
            ${createCell('Material')}
            ${createCell('Labor')}
            ${createCell('Equipment')}
            ${createCell('Sub-Contract')}
            ${createCell('Line Total')}
        </Row>
    `;

    let currentRow = 9; // Project Info (6) + Empty (1) + Header (1) + 1
    let dataRows = '';
    const lineTotalRowIndices: number[] = [];

    divisions.forEach(div => {
        const itemsWithValues = div.items.filter(item => 
            (item.material + item.labor + item.equipment + item.subContract) > 0 || item.description.trim() !== '' || item.service.trim() !== ''
        );

        if (itemsWithValues.length > 0) {
            dataRows += `
                <Row ss:StyleID="sDivision">
                    <Cell ss:MergeAcross="8"><Data ss:Type="String">${escapeXml(`${div.costCode} - ${div.title}`)}</Data></Cell>
                </Row>
            `;
            currentRow++;

            itemsWithValues.forEach(item => {
                const lineTotal = (item.material + item.labor + item.equipment + item.subContract) * (1 + projectInfo.add / 100);
                // Formula for Column I: (Sum of E, F, G, H) * (1 + B5/100)
                // In R1C1: (RC[-4]+RC[-3]+RC[-2]+RC[-1]) * (1 + R5C2/100)
                const lineFormula = `=(RC[-4]+RC[-3]+RC[-2]+RC[-1])*(1+R5C2/100)`;

                dataRows += `
                    <Row>
                        ${createCell('')}
                        ${createCell(item.costCode)}
                        ${createCell(item.service)}
                        ${createCell(item.description)}
                        ${createCell(item.material, 'Number', 'sCurrency')}
                        ${createCell(item.labor, 'Number', 'sCurrency')}
                        ${createCell(item.equipment, 'Number', 'sCurrency')}
                        ${createCell(item.subContract, 'Number', 'sCurrency')}
                        ${createCell(lineTotal, 'Number', 'sCurrencyBold', lineFormula)}
                    </Row>
                `;
                lineTotalRowIndices.push(currentRow);
                currentRow++;
            });
        }
    });

    // Create the SUM range for Column I (Line Totals)
    // We use a specific list of rows if needed, but a simple SUM(R9C9:R[current]C9) works too if headers don't have numbers
    const subtotalFormula = lineTotalRowIndices.length > 0 
        ? `=SUM(${lineTotalRowIndices.map(r => `R${r}C9`).join(',')})`
        : '=0';

    // Current row pointers for summary
    const subtotalRowNum = currentRow + 2;
    const marginRowNum = currentRow + 3;
    const grandTotalRowNum = currentRow + 4;

    const summaryRows = `
        <Row></Row>
        <Row>
            ${createEmptyCells(7)}
            ${createCell('Subtotal', 'String', 'sRightAlign')}
            ${createCell(subTotal, 'Number', 'sCurrencyBold', subtotalFormula)}
        </Row>
        <Row>
            ${createEmptyCells(7)}
            ${createCell(`Margin (%)`, 'String', 'sRightAlign')}
            ${createCell(marginAmount, 'Number', 'sCurrency', `=RC[-1]*(R6C2/100)`)}
        </Row>
        <Row>
            ${createEmptyCells(7)}
            ${createCell('Grand Total', 'String', 'sGrandTotalLabel')}
            ${createCell(grandTotal, 'Number', 'sGrandTotalValue', `=R${subtotalRowNum}C9+R${marginRowNum}C9`)}
        </Row>
        <Row></Row>
        <Row>
            ${createEmptyCells(7)}
            ${createCell('Total Cost per SQFT', 'String', 'sRightAlign')}
            ${createCell(grandTotal / (projectInfo.squareFeet || 1), 'Number', 'sCurrency', `=R${grandTotalRowNum}C9/R4C2`)}
        </Row>
        <Row>
            ${createEmptyCells(7)}
            ${createCell('Cost per Room', 'String', 'sRightAlign')}
            ${createCell(grandTotal / (projectInfo.rooms || 1), 'Number', 'sCurrency', `=R${grandTotalRowNum}C9/R3C2`)}
        </Row>
    `;

    return `<?xml version="1.0" encoding="UTF-8"?>
<?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
    xmlns:o="urn:schemas-microsoft-com:office:office"
    xmlns:x="urn:schemas-microsoft-com:office:excel"
    xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"
    xmlns:html="http://www.w3.org/TR/REC-html40">
    <Styles>
        <Style ss:ID="Default" ss:Name="Normal">
            <Alignment ss:Vertical="Bottom"/>
            <Borders/>
            <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="11" ss:Color="#000000"/>
            <Interior/>
            <NumberFormat/>
            <Protection/>
        </Style>
        <Style ss:ID="sBold">
            <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="11" ss:Bold="1"/>
        </Style>
        <Style ss:ID="sRightAlign">
            <Alignment ss:Horizontal="Right" ss:Vertical="Bottom"/>
            <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="10" ss:Color="#666666"/>
        </Style>
        <Style ss:ID="sHeader">
            <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="11" ss:Color="#FFFFFF" ss:Bold="1"/>
            <Interior ss:Color="#3F51B5" ss:Pattern="Solid"/>
            <Alignment ss:Horizontal="Center" ss:Vertical="Bottom"/>
        </Style>
        <Style ss:ID="sDivision">
            <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="11" ss:Color="#000000" ss:Bold="1"/>
            <Interior ss:Color="#F1F5F9" ss:Pattern="Solid"/>
            <Borders>
                <Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E2E8F0"/>
            </Borders>
        </Style>
        <Style ss:ID="sCurrency">
            <NumberFormat ss:Format="&quot;$&quot;#,##0.00"/>
        </Style>
        <Style ss:ID="sCurrencyBold">
            <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="11" ss:Bold="1"/>
            <NumberFormat ss:Format="&quot;$&quot;#,##0.00"/>
        </Style>
        <Style ss:ID="sGrandTotalLabel">
             <Alignment ss:Horizontal="Right" ss:Vertical="Bottom"/>
             <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="12" ss:Color="#000000" ss:Bold="1"/>
             <Borders>
                <Border ss:Position="Top" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#000000"/>
             </Borders>
        </Style>
        <Style ss:ID="sGrandTotalValue">
             <Font ss:FontName="Calibri" x:Family="Swiss" ss:Size="12" ss:Color="#3F51B5" ss:Bold="1"/>
             <NumberFormat ss:Format="&quot;$&quot;#,##0.00"/>
             <Borders>
                <Border ss:Position="Top" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#000000"/>
             </Borders>
        </Style>
    </Styles>
    <Worksheet ss:Name="Estimate">
        <Table>
            <Column ss:AutoFitWidth="0" ss:Width="160"/>
            <Column ss:AutoFitWidth="0" ss:Width="80"/>
            <Column ss:AutoFitWidth="0" ss:Width="200"/>
            <Column ss:AutoFitWidth="0" ss:Width="250"/>
            <Column ss:AutoFitWidth="0" ss:Width="80"/>
            <Column ss:AutoFitWidth="0" ss:Width="80"/>
            <Column ss:AutoFitWidth="0" ss:Width="80"/>
            <Column ss:AutoFitWidth="0" ss:Width="80"/>
            <Column ss:AutoFitWidth="0" ss:Width="100"/>
            ${projectInfoRows}
            <Row><Cell/></Row> 
            ${headerRow}
            ${dataRows}
            ${summaryRows}
        </Table>
    </Worksheet>
</Workbook>`.trim();
};
